+
+	for _, file := range files {
+		if !strings.HasSuffix(filepath.Base(file), suffix) {
+			continue
+		}
+		if fallback == "" {
+			fallback = file
+		}
+
+		info, err := os.Stat(file)
+		if err != nil {
+			continue
+		}
+		modTime := info.ModTime().UnixNano()
+		if bestPath == "" || modTime > bestModTime {
+			bestPath = file
+			bestModTime = modTime
+		}
+	}
+
+	if bestPath != "" {
+		return bestPath, true
+	}
+	if fallback != "" {
+		return fallback, true
+	}
+
+	return "", false
+}
