+			return "", false, err
+		}
+		matches, err := sessionFileMatchesCWD(ctx, file, workspacePath)
+		if err != nil || !matches {
+			continue
+		}
+
+		info, err := os.Stat(file)
+		if err != nil {
+			if bestPath == "" {
+				bestPath = file
+			}
+			continue
+		}
+		modTime := info.ModTime().UnixNano()
+		if bestPath == "" || modTime > bestModTime {
