	registry := plugin.NewRegistry()
	if err := registerBuiltInPlugins(registry); err != nil {
		return err
	}

	listener, err := net.Listen("tcp", cfg.Addr)
	if err != nil {
		return err
	}

	appServer := server.New(server.Config{
