    // (single hook def == ours). With multiple defs the entry is shared
    // with a user hook; changing the matcher would change when their hook
    // fires.
    if (hooksList.length === 1) {
      entry["matcher"] = reg.matcher;
    }
  }

  hooks[reg.event] = entries;
